+/*
+ * @test
+ * @bug 8358772
+ * @summary Demonstrate the use of VectorTypes (Vector API) form the Template Library.
+ * @modules java.base/jdk.internal.misc
+ * @modules jdk.incubator.vector
+ * @library /test/lib /
